
CREATE
    OR REPLACE PROCEDURE public.sp_truncate_and_insert_open_corporates_standard()
    LANGUAGE plpgsql AS
$$
BEGIN
    DROP TABLE IF EXISTS datascience.open_corporates_standard;
    CREATE TABLE datascience.open_corporates_standard
        DISTSTYLE EVEN
        INTERLEAVED
            SORTKEY
            (
            company_number,
            normalised_name,
            street_address_normalized
            ) AS
    WITH -- CTE for determining and filtering on country
         country_filter AS (SELECT
                                company_number,
                                jurisdiction_code,
                                COALESCE(
                                        REGEXP_REPLACE(
                                                NULLIF("registered_address.region", ''),
                                                '[^a-zA-Z ]'
                                        ),
                                        CASE
                                            WHEN LEN(jurisdiction_code) = 5 THEN UPPER(RIGHT(jurisdiction_code, 2))
                                            ELSE NULL
                                        END
                                )                                AS "region",
                                COALESCE(
                                        CASE
                                            WHEN UPPER("registered_address.country") IN (
                                                                                         'US',
                                                                                         'UNITED STATES',
                                                                                         'UNITED STATES OF AMERICA',
                                                                                         'USA',
                                                                                         'PUERTO RICO'
                                                ) THEN 'US'
                                            WHEN UPPER("registered_address.country") IN ('CANADA', 'CAN', 'CA')
                                                THEN 'CA'
                                            WHEN UPPER("registered_address.country") IN (
                                                                                         'UNITED KINGDOM',
                                                                                         'ENGLAND',
                                                                                         'SCOTLAND',
                                                                                         'WALES',
                                                                                         'NORTHERN IRELAND',
                                                                                         'UK',
                                                                                         'GREAT BRITAIN'
                                                ) THEN 'GB'
                                            WHEN UPPER("registered_address.country") IN ('IRELAND', 'IRLANDE', 'IRLAND')
                                                THEN 'IE'
                                            ELSE NULL
                                        END,
                                        CASE
                                            WHEN UPPER(LEFT(jurisdiction_code, 2)) IN ('US', 'CA', 'GB', 'IE')
                                                THEN UPPER(LEFT(jurisdiction_code, 2))
                                            ELSE NULL
                                        END
                                )                                AS base_country,
                                "registered_address.postal_code" AS postal_code,
                                REGEXP_REPLACE(
                                        UPPER("registered_address.street_address"),
                                        '[^A-Z 0-9,]'
                                )                                AS address_string
                            FROM dev.open_corporate.companies
                            WHERE base_country IS NOT NULL
                            UNION
                            DISTINCT
                            SELECT
                                company_number,
                                jurisdiction_code,
                                COALESCE(
                                        REGEXP_REPLACE(NULLIF("region", ''), '[^a-zA-Z ]'),
                                        CASE
                                            WHEN LEN(jurisdiction_code) = 5 THEN UPPER(RIGHT(jurisdiction_code, 2))
                                            ELSE NULL
                                        END
                                )                                                    AS "region",
                                COALESCE(
                                        CASE
                                            WHEN UPPER("country") IN (
                                                                      'US',
                                                                      'UNITED STATES',
                                                                      'UNITED STATES OF AMERICA',
                                                                      'USA',
                                                                      'PUERTO RICO'
                                                ) THEN 'US'
                                            WHEN UPPER("country") IN ('CANADA', 'CAN', 'CA') THEN 'CA'
                                            WHEN UPPER("country") IN (
                                                                      'UNITED KINGDOM',
                                                                      'ENGLAND',
                                                                      'SCOTLAND',
                                                                      'WALES',
                                                                      'NORTHERN IRELAND',
                                                                      'UK',
                                                                      'GREAT BRITAIN'
                                                ) THEN 'GB'
                                            WHEN UPPER("country") IN ('IRELAND', 'IRLANDE', 'IRLAND') THEN 'IE'
                                            ELSE NULL
                                        END,
                                        CASE
                                            WHEN UPPER(LEFT(jurisdiction_code, 2)) IN ('US', 'CA', 'GB', 'IE')
                                                THEN UPPER(LEFT(jurisdiction_code, 2))
                                            ELSE NULL
                                        END
                                )                                                    AS base_country,
                                postal_code,
                                REGEXP_REPLACE(UPPER(street_address), '[^A-Z 0-9,]') AS address_string
                            FROM dev.open_corporate.non_reg_addresses
                            WHERE base_country IS NOT NULL
         ),
         regions_first AS (SELECT
                               company_number,
                               jurisdiction_code,
                               CASE base_country
                                   WHEN 'GB' THEN REGEXP_SUBSTR(SPLIT_PART(UPPER(postal_code), ' ', 1), '^([A-Z]*)')
                                   WHEN 'IE' THEN SPLIT_PART(
                                           REGEXP_SUBSTR(
                                                   address_string,
                                                   ',? ([A-Z 0-9]*)$|, ?([A-Z 0-9]*), ?IRELAND',
                                                   1,
                                                   1,
                                                   'e'
                                           ),
                                           ' ',
                                           1
                                                  )
                                   ELSE COALESCE(region_code, "region")
                               END          AS "region",
                               base_country AS country
                           FROM country_filter AS base
                               LEFT JOIN datascience.ml_regions AS reg
                                       ON base.base_country = reg.country_code
                                   AND UPPER(base."region") = reg.region_name_upper
         ),
         regions AS (SELECT
                         company_number,
                         jurisdiction_code,
                         COALESCE(ie."region", base."region") AS "region",
                         country
                     FROM regions_first AS base
                         LEFT JOIN datascience.ml_ireland AS ie
                                 ON LEFT(base."region", 3) = ie.postal_code_prefix
         ),
         -- CTE for standardizing and filtering regions
         businesses AS (SELECT
                            company_number,
                            jurisdiction_code,
                            "region",
                            country
                        FROM regions AS base
                            INNER JOIN datascience.ml_regions AS reg
                                    ON base.country = reg.country_code
                                AND base."region" = reg.region_code
         ),
         names AS (
             -- CTE for selecting distinct names
             SELECT
                 base.company_number,
                 base.jurisdiction_code,
                 base.name AS company_name
             FROM open_corporate.alternative_names AS base
                 INNER JOIN businesses
                         USING (company_number, jurisdiction_code)
             WHERE base.name <> ''
               AND base.name IS NOT NULL
             UNION ALL
             SELECT
                 base.company_number,
                 base.jurisdiction_code,
                 base.name AS company_name
             FROM open_corporate.companies AS base
                 INNER JOIN businesses
                         USING (company_number, jurisdiction_code)
             WHERE base.name <> ''
               AND base.name IS NOT NULL
             UNION ALL
             SELECT
                 base.company_number,
                 base.jurisdiction_code,
                 base.current_alternative_legal_name AS company_name
             FROM open_corporate.companies AS base
                 INNER JOIN businesses
                         USING (company_number, jurisdiction_code)
             WHERE current_alternative_legal_name_language = 'en'
               AND base.current_alternative_legal_name <> ''
               AND base.current_alternative_legal_name IS NOT NULL
             UNION ALL
             SELECT
                 base.company_number,
                 base.jurisdiction_code,
                 base.normalised_name AS company_name
             FROM open_corporate.companies AS base
                 INNER JOIN businesses
                         USING (company_number, jurisdiction_code)
             WHERE base.normalised_name <> ''
               AND base.normalised_name IS NOT NULL
             UNION ALL
             -- UNNESTING the previous names field
             SELECT
                 company_number,
                 jurisdiction_code,
                 CAST(name_array[ordinal] AS VARCHAR) AS company_name
             FROM (SELECT
                       base.company_number,
                       base.jurisdiction_code,
                       split_to_array(base.previous_names, '|') AS name_array
                   FROM open_corporate.companies AS base
                       INNER JOIN businesses
                               USING (company_number, jurisdiction_code)
                   WHERE base.previous_names <> ''
                     AND base.previous_names IS NOT NULL
             ) AS base
                 CROSS JOIN datascience.ml_number1k
             WHERE ordinal < get_array_length(name_array)
         ),
         normalized_names AS (SELECT DISTINCT
                                  company_number,
                                  jurisdiction_code,
                                  public.sanitize_business_name(company_name) AS company_name,
                                  public.canonize_business_name(company_name) AS normalized_name
                              FROM names
         ),
         addresses AS (SELECT
                           base.company_number,
                           base.jurisdiction_code,
                           NULLIF("registered_address.street_address", '') AS street_address,
                           NULLIF("registered_address.locality", '')       AS city,
                           busi.region,
                           NULLIF("registered_address.postal_code", '')    AS postal_code,
                           busi.country
                       FROM open_corporate.companies AS base
                           INNER JOIN businesses AS busi
                                   USING (company_number, jurisdiction_code)
                       UNION
                       DISTINCT
                       SELECT
                           base.company_number,
                           base.jurisdiction_code,
                           NULLIF(street_address, '') AS street_address,
                           NULLIF(locality, '')       AS city,
                           busi.region,
                           NULLIF(postal_code, '')    AS postal_code,
                           busi.country
                       FROM open_corporate.non_reg_addresses AS base
                           INNER JOIN businesses AS busi
                                   USING (company_number, jurisdiction_code)
         ),
         normalized_addresses AS (SELECT
                                      company_number,
                                      jurisdiction_code,
                                      base.country,
                                      base.region,
                                      street_address,
                                      TRIM(
                                              REPLACE(
                                                      REPLACE(
                                                              REPLACE(
                                                                      REPLACE(
                                                                              REPLACE(
                                                                                      REPLACE(
                                                                                              REPLACE(
                                                                                                      REPLACE(
                                                                                                              REPLACE(
