                                              )
                                      )                                        AS street_address_normalized,
                                      REGEXP_SUBSTR(street_address, '^[0-9]+') AS street_number,
                                      CASE base.country
                                          WHEN 'US' THEN LPAD(SPLIT_PART(TRIM(postal_code), '-', 1), 5, '0')
                                          WHEN 'CA' THEN REGEXP_REPLACE(UPPER(postal_code), '[^A-Z0-9]')
                                          WHEN 'GB' THEN REGEXP_REPLACE(UPPER(postal_code), '[^A-Z0-9]')
                                          ELSE NULL
                                      END                                      AS postal_code,
                                      SPLIT_PART(TRIM(postal_code), '-', 2)    AS zipcode_plus4,
                                      TRIM(
                                              REPLACE(
                                                      REPLACE(
                                                              REPLACE(
                                                                      REGEXP_REPLACE(TRANSLATE(UPPER(city),
                                                                                               'ÂÁÀÃÄÉÈÊËÍÌÎÏÓÒÕÖÔÚÙÛÜÇ',
                                                                                               'AAAAAEEEEIIIIOOOOOUUUUC'),
                                                                                     '[^A-Z 0-9]', ''),
                                                                      ' ',
                                                                      '$#'
                                                              ),
                                                              '#$',
                                                              ''
                                                      ),
                                                      '$#',
                                                      ' '
                                              )
                                      )                                        AS city
                                  FROM addresses AS base
                                  WHERE street_address IS NOT NULL
                                    AND street_address <> ''
         ),
         other_data AS (SELECT DISTINCT
                            company_number,
                            jurisdiction_code,
                            previous_names,
                            incorporation_date,
                            dissolution_date,
                            '' AS website_normalized
                        FROM businesses AS busi
                            INNER JOIN dev.open_corporate.companies AS base
                                    USING (company_number, jurisdiction_code)
         )
    SELECT DISTINCT
        company_number,
        jurisdiction_code,
        company_name,
        normalized_name          AS normalised_name,
        company_name             AS current_alternative_legal_name,
        company_name             AS alternative_name,
        previous_names,
        incorporation_date,
        dissolution_date,
        street_address,
        normalized_name          AS dba_normalized,
        normalized_name          AS companyname_normalized,
        company_name             AS alternative_dba_normalized,
        country                  AS country_normalized,
        country,
        country                  AS country_code,
        city,
        city                     AS locality,
        "region",
        "region"                 AS state_abbreviation,
        street_address_normalized,
        postal_code,
        postal_code              AS zipcode,
        LEFT(normalized_name, 1) AS dba_firstletter,
        LEFT(company_name, 1)    AS companyname_firstletter,
        LEFT(postal_code, 3)     AS zipcode_threedigits,
        zipcode_plus4,
        website_normalized,
        street_number
    FROM normalized_names AS names
        INNER JOIN normalized_addresses AS addresses
                USING (company_number, jurisdiction_code)
        INNER JOIN other_data AS other
                USING (company_number, jurisdiction_code);

    GRANT ALL ON TABLE datascience.open_corporates_standard TO GROUP worth_ds;
END
